class Solution(object):
    def toHex(self, num):
        if num == 0:
            return '0'
        hex_chars = '0123456789abcdef'
        result = ''
        if num < 0:
            num = (1 << 32) + num
        while num:
            result = hex_chars[num & 15] + result
            num >>= 4
        return result
